public int minCostII(int[][] costs) {
    if (costs.length == 0) return 0;
    int n = costs.length, k = costs[0].length;
    int min1 = 0, min2 = 0, minColor = -1;

    for (int i = 0; i < n; i++) {
        int newMin1 = Integer.MAX_VALUE, newMin2 = Integer.MAX_VALUE, newColor = -1;
        for (int j = 0; j < k; j++) {
            int cost = costs[i][j] + (j == minColor ? min2 : min1);
            if (cost < newMin1) { newMin2 = newMin1; newMin1 = cost; newColor = j; }
            else if (cost < newMin2) newMin2 = cost;
        }
        min1 = newMin1; min2 = newMin2; minColor = newColor;
    }

    return min1;
}

