from typing import List

def min_cost_ii(costs: List[List[int]]) -> int:
    if not costs: return 0
    min1, min2, min_color = 0, 0, -1

    for row in costs:
        new_min1, new_min2, new_color = float('inf'), float('inf'), -1
        for j, cost in enumerate(row):
            total = cost + (min2 if j == min_color else min1)
            if total < new_min1:
                new_min2, new_min1, new_color = new_min1, total, j
            elif total < new_min2:
                new_min2 = total
        min1, min2, min_color = new_min1, new_min2, new_color

    return min1
